## 6. Dynamic Content Creation

For list-based UIs, widgets create UI elements dynamically:

```cpp
void ULFPShopWidget::RefreshRelicList()
{
    RelicButtons.Empty();
    ButtonToRelicIndexMap.Empty();

    if (Box_RelicList) Box_RelicList->ClearChildren();

    for (int32 i = 0; i < CachedShopDefinition.RelicList.Num(); ++i)
    {
        const FLFPShopRelicEntry& Entry = CachedShopDefinition.RelicList[i];

        // Create button dynamically
        UButton* RelicButton = NewObject<UButton>(this);
        if (!RelicButton) continue;

        // Create and add child widget
        UTextBlock* Label = NewObject<UTextBlock>(RelicButton);
        if (Label)
        {
            Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d"), 
                *RelicDefinition.DisplayName.ToString(), Entry.Price)));
            RelicButton->AddChild(Label);
        }

        // Add to container
        UVerticalBoxSlot* ItemSlot = Box_RelicList->AddChildToVerticalBox(RelicButton);
        if (ItemSlot) ItemSlot->SetPadding(FMargin(4.f));

        // Bind click event
        RelicButton->OnClicked.AddDynamic(this, &ULFPShopWidget::OnRelicButtonClicked);

        // Track button for later reference
        RelicButtons.Add(RelicButton);
        ButtonToNodeIDMap.Add(RelicButton, i);  // Map button to data index
    }
}
```

**Key techniques**:
- Use `NewObject<>()` to create widgets dynamically
- Use container's `AddChildToVerticalBox()` or `AddChildToHorizontalBox()`
- Store button references in arrays for later lookup
- Create mapping from UI element to data index

