#pragma once

#include "CoreMinimal.h"
#include "GameFramework/PlayerController.h"
#include "InputActionValue.h"
#include "LFP2D/Town/LFPTownData.h"
#include "LFPWorldMapPlayerController.generated.h"

class ALFPWorldMapManager;
class ALFPWorldMapNode;
class ULFPWorldMapEditorComponent;
class ULFPWorldMapEditorWidget;
class ULFPUnitMergeWidget;
class ULFPShopWidget;
class ULFPHireMarketWidget;
class ULFPTownWidget;
class ULFPTeleportWidget;
class UInputMappingContext;
class UInputAction;

/**
 * 世界地图玩家控制器
 * 负责世界地图上的玩家交互、节点选择、移动等
 */
UCLASS()
class LFP2D_API ALFPWorldMapPlayerController : public APlayerController
{
	GENERATED_BODY()

public:
	ALFPWorldMapPlayerController();

protected:
	virtual void BeginPlay() override;
	virtual void SetupInputComponent() override;
	virtual void Tick(float DeltaTime) override;

public:
	// ============== 输入处理 ==============

	void OnConfirmAction(const FInputActionValue& Value);
	void OnCancelAction(const FInputActionValue& Value);
	void OnToggleEditorAction(const FInputActionValue& Value);

	// 相机操作
	void OnCameraPan(const FInputActionValue& Value);
	void OnCameraDragStarted(const FInputActionValue& Value);
	void OnCameraDragTriggered(const FInputActionValue& Value);
	void OnCameraDragCompleted(const FInputActionValue& Value);
	void OnCameraZoom(const FInputActionValue& Value);

	// ============== 节点交互 ==============

	// 选中节点
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void SelectNode(ALFPWorldMapNode* Node);

	// 移动到相邻节点
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void MoveToNode(ALFPWorldMapNode* Node);

	// 显示可达节点高亮
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void ShowReachableNodes();

	// 清除可达节点高亮
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void ClearReachableHighlight();

	// 进入节点（触发战斗/事件等）
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void EnterNode(ALFPWorldMapNode* Node);

	// 进入战斗（保存快照 + 设置请求 + 切换关卡）
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void EnterBattle(ALFPWorldMapNode* BattleNode);

	// 获取世界地图管理器
	UFUNCTION(BlueprintPure, Category = "World Map")
	ALFPWorldMapManager* GetWorldMapManager() const;

protected:
	// ============== 输入系统 ==============

	UPROPERTY(EditAnywhere, Category = "Input")
	TObjectPtr<UInputMappingContext> DefaultInputMapping;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* ConfirmAction;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* CancelAction;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* ToggleEditorAction;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* CameraPanAction;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* CameraDragAction;

	UPROPERTY(EditAnywhere, Category = "Input")
	UInputAction* CameraZoomAction;

	// ============== 世界地图编辑器 ==============

	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "World Map Editor")
	TObjectPtr<ULFPWorldMapEditorComponent> WorldMapEditorComponent;

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPWorldMapEditorWidget> WorldMapEditorWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPWorldMapEditorWidget> WorldMapEditorWidget;

	// ============== 升华塔（升阶面板） ==============

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPUnitMergeWidget> UnitMergeWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPUnitMergeWidget> UnitMergeWidget;

	// 打开升阶面板
	void OpenEvolutionTower();

	// 升阶面板关闭回调
	UFUNCTION()
	void OnUnitMergeWidgetClosed();

	// ============== 商店 ==============

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPShopWidget> ShopWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPShopWidget> ShopWidget;

	void OpenShop(ALFPWorldMapNode* ShopNode, bool bReturnToTownOnClose);

	UFUNCTION()
	void OnShopWidgetClosed();

	// ============== 雇佣市场 ==============

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPHireMarketWidget> HireMarketWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPHireMarketWidget> HireMarketWidget;

	void OpenHireMarket(ALFPWorldMapNode* HireMarketNode, bool bReturnToTownOnClose);

	UFUNCTION()
	void OnHireMarketWidgetClosed();

	// ============== 城镇系统 ==============

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPTownWidget> TownWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPTownWidget> TownWidget;

	// 打开城镇面板
	void OpenTown(ALFPWorldMapNode* TownNode);

	// 城镇面板关闭回调
	UFUNCTION()
	void OnTownWidgetClosed();

	// 城镇建筑功能请求回调
	UFUNCTION()
	void OnTownBuildingRequested(ELFPTownBuildingType BuildingType);

	// ============== 传送阵 ==============

	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "UI")
	TSubclassOf<ULFPTeleportWidget> TeleportWidgetClass;

	UPROPERTY()
	TObjectPtr<ULFPTeleportWidget> TeleportWidget;

	void OpenTeleport();

	UFUNCTION()
	void OnTeleportTargetSelected(int32 TargetNodeID);

	UFUNCTION()
	void OnTeleportWidgetClosed();

	// ============== 相机 ==============

	// 相机俯视角度（Pitch，负值向下看）
	UPROPERTY(EditAnywhere, Category = "Camera")
	float CameraPitchAngle = -60.0f;

	UPROPERTY(EditAnywhere, Category = "Camera")
	float CameraPanSpeed = 500.0f;

	UPROPERTY(EditAnywhere, Category = "Camera")
	float CameraDragSpeed = 10.0f;

	UPROPERTY(EditAnywhere, Category = "Camera")
	float CameraZoomSpeed = 100.0f;

	UPROPERTY(EditAnywhere, Category = "Camera")
	float MinZoomDistance = 300.0f;

	UPROPERTY(EditAnywhere, Category = "Camera")
	float MaxZoomDistance = 2000.0f;

	float CurrentZoom = 1000.0f;
	FVector CameraOffset;

	// 场景切换后首帧跳过相机平滑插值
	bool bSnapCameraNextFrame = true;

	// 拖拽状态
	bool bIsDragging = false;
	FVector2D DragStartPosition;
	float DragTime = 0.f;

	UPROPERTY(EditAnywhere, Category = "Input")
	float DragThresholdTime = 0.5f;

	// ============== 状态 ==============

	// 当前选中的节点
	UPROPERTY()
	TObjectPtr<ALFPWorldMapNode> SelectedNode;

	// 玩家移动的目标节点（移动完成后自动进入）
	UPROPERTY()
	TObjectPtr<ALFPWorldMapNode> PendingEnterNode;

	// 可达节点缓存（高亮用）
	TArray<ALFPWorldMapNode*> ReachableNodes;

	// 当前商店关闭后是否返回城镇
	bool bReturnToTownAfterShopClose = false;

	// 当前雇佣市场关闭后是否返回城镇
	bool bReturnToTownAfterHireMarketClose = false;

	// 棋子移动完成回调
	UFUNCTION()
	void OnPawnMoveCompleted();

	// 世界地图管理器缓存
	UPROPERTY()
	mutable TObjectPtr<ALFPWorldMapManager> CachedWorldMapManager;
};

#pragma once

#include "CoreMinimal.h"
#include "UObject/NoExportTypes.h"
#include "LFPWorldMapPlayerState.generated.h"

class ALFPWorldMapManager;
class ALFPWorldMapNode;

DECLARE_DYNAMIC_MULTICAST_DELEGATE_TwoParams(FOnWorldMapTurnChanged, int32, CurrentTurn, int32, TurnBudget);
DECLARE_DYNAMIC_MULTICAST_DELEGATE_OneParam(FOnPlayerNodeChanged, ALFPWorldMapNode*, NewNode);

/**
 * 世界地图玩家状态：追踪位置、回合消耗、访问/揭露节点
 * 由 WorldMapManager 持有
 */
UCLASS(Blueprintable, BlueprintType)
class LFP2D_API ULFPWorldMapPlayerState : public UObject
{
	GENERATED_BODY()

public:
	// 当前所在节点 ID
	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "World Map")
	int32 CurrentNodeID = 0;

	// 已消耗的总回合数
	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "World Map")
	int32 CurrentTurn = 0;

	// 回合压力阈值（超过后全局难度递增）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "World Map")
	int32 TurnPressureThreshold = 100;

	// 已访问节点集合
	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "World Map")
	TSet<int32> VisitedNodeIDs;

	// 已揭露节点集合（永久可见）
	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "World Map")
	TSet<int32> RevealedNodeIDs;

	// ============== 方法 ==============

	// 移动到相邻节点（验证边存在、消耗回合、更新位置）
	UFUNCTION(BlueprintCallable, Category = "World Map")
	bool MoveToNode(int32 TargetNodeID, ALFPWorldMapManager* Manager);

	// 获取从当前节点出发的可达节点 ID 列表
	UFUNCTION(BlueprintCallable, Category = "World Map")
	TArray<int32> GetReachableNodeIDs(ALFPWorldMapManager* Manager) const;

	// 是否超过压力阈值
	UFUNCTION(BlueprintPure, Category = "World Map")
	bool IsPastPressureThreshold() const { return CurrentTurn >= TurnPressureThreshold; }

	// 直接设置当前节点（传送用，不校验相邻、不消耗回合）
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void SetCurrentNodeDirectly(int32 TargetNodeID, ALFPWorldMapNode* TargetNode);

	// 初始化（设置起始节点）
	UFUNCTION(BlueprintCallable, Category = "World Map")
	void Initialize(int32 StartNodeID);

	// ============== 委托 ==============

	UPROPERTY(BlueprintAssignable)
	FOnWorldMapTurnChanged OnTurnChanged;

	UPROPERTY(BlueprintAssignable)
	FOnPlayerNodeChanged OnPlayerNodeChanged;
};

#pragma once

#include "CoreMinimal.h"
#include "Engine/GameInstance.h"
#include "LFP2D/Unit/LFPUnitTypes.h"
#include "LFP2D/Shop/LFPRelicTypes.h"
#include "LFP2D/Shop/LFPHireMarketTypes.h"
#include "LFPGameInstance.generated.h"

class ALFPTacticsUnit;
class ULFPUnitRegistryDataAsset;
class ULFPRelicDataAsset;
class ULFPShopDataAsset;
class ULFPHireMarketDataAsset;

// 战斗请求：世界地图 → 战斗场景传递的数据
USTRUCT(BlueprintType)
struct FLFPBattleRequest
{
	GENERATED_BODY()

	// 触发战斗的节点 ID
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	int32 SourceNodeID = -1;

	// 战斗地图 CSV 文件名（对应 Saved/Maps/ 下的 CSV）
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	FString BattleMapName;

	// 敌人星级
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	int32 StarRating = 1;

	// 是否可逃跑
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bCanEscape = true;

	// 节点基础金币奖励
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Battle")
	int32 BaseGoldReward = 0;

	// 节点基础食物奖励
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Battle")
	int32 BaseFoodReward = 0;

	// 是否有有效请求
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bIsValid = false;
};

// 战斗结果：战斗场景 → 世界地图传递的数据
USTRUCT(BlueprintType)
struct FLFPBattleResult
{
	GENERATED_BODY()

	// 对应的节点 ID
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	int32 SourceNodeID = -1;

	// 是否胜利
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bVictory = false;

	// 是否逃跑
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bEscaped = false;

	// 战斗中捕获的单位列表（背叛系统触发）
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	TArray<FLFPUnitEntry> CapturedUnits;

	// 总金币奖励（基础 + 击杀掉落）
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	int32 GoldReward = 0;

	// 总食物奖励（基础 + 击杀掉落）
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	int32 FoodReward = 0;

	// 是否有有效结果
	UPROPERTY(BlueprintReadWrite, Category = "Battle")
	bool bIsValid = false;
};

// 世界地图状态快照：跨关卡保持
USTRUCT(BlueprintType)
struct FLFPWorldMapSnapshot
{
	GENERATED_BODY()

	// 当前世界地图名
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	FString WorldMapName;

	// 玩家当前节点 ID
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	int32 CurrentNodeID = 0;

	// 已消耗回合数
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	int32 CurrentTurn = 0;

	// 已访问节点
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	TSet<int32> VisitedNodeIDs;

	// 已揭露节点
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	TSet<int32> RevealedNodeIDs;

	// 已触发节点（战斗/事件/Boss 首次触发后不再触发）
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	TSet<int32> TriggeredNodeIDs;

	// 是否有有效快照
	UPROPERTY(BlueprintReadWrite, Category = "World Map")
	bool bIsValid = false;
};

/**
 * 游戏实例：跨关卡生命周期
 * 负责世界地图 ↔ 战斗场景之间的状态传递
 */
UCLASS()
class LFP2D_API ULFPGameInstance : public UGameInstance
{
	GENERATED_BODY()

public:
	// ============== 战斗请求/结果 ==============

	// 设置战斗请求（世界地图调用，进入战斗前）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	void SetBattleRequest(const FLFPBattleRequest& Request);

	// 获取战斗请求（战斗场景调用，读取后清除）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	FLFPBattleRequest ConsumeBattleRequest();

	// 设置战斗结果（战斗场景调用，结束战斗时）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	void SetBattleResult(const FLFPBattleResult& Result);

	// 获取战斗结果（世界地图调用，读取后清除）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	FLFPBattleResult ConsumeBattleResult();

	// ============== 世界地图快照 ==============

	// 保存世界地图状态快照
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	void SaveWorldMapSnapshot(const FLFPWorldMapSnapshot& Snapshot);

	// 获取世界地图快照（不清除，世界地图关卡可多次读取）
	UFUNCTION(BlueprintPure, Category = "Scene Transition")
	const FLFPWorldMapSnapshot& GetWorldMapSnapshot() const { return WorldMapSnapshot; }

	// 是否有待处理的战斗结果
	UFUNCTION(BlueprintPure, Category = "Scene Transition")
	bool HasPendingBattleResult() const { return PendingBattleResult.bIsValid; }

	// ============== 场景切换 ==============

	// 切换到战斗场景（带淡出过场）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	void TransitionToBattle(const FString& BattleLevelName);

	// 切换回世界地图（带淡出过场）
	UFUNCTION(BlueprintCallable, Category = "Scene Transition")
	void TransitionToWorldMap(const FString& WorldMapLevelName);

	// 过场动画时长（秒）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Scene Transition")
	float TransitionFadeDuration = 0.5f;

	// 是否正在过场中（防止重复触发）
	UPROPERTY(BlueprintReadOnly, Category = "Scene Transition")
	bool bIsTransitioning = false;

	// 世界地图关卡名（蓝图中配置，默认值）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Scene Transition")
	FString DefaultWorldMapLevelName = TEXT("Test_WorldMap");

	// 战斗关卡名（蓝图中配置，默认值）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Scene Transition")
	FString DefaultBattleLevelName = TEXT("Test_Fight");

	// ============== 编队系统 ==============

	// ============== 资源系统 ==============

	// 金币
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Resources")
	int32 Gold = 0;

	// 食物
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Resources")
	int32 Food = 0;

	// 增加金币
	UFUNCTION(BlueprintCallable, Category = "Resources")
	void AddGold(int32 Amount);

	// 增加食物
	UFUNCTION(BlueprintCallable, Category = "Resources")
	void AddFood(int32 Amount);

	// 获取金币
	UFUNCTION(BlueprintPure, Category = "Resources")
	int32 GetGold() const { return Gold; }

	// 获取食物
	UFUNCTION(BlueprintPure, Category = "Resources")
	int32 GetFood() const { return Food; }

	// 是否有足够金币
	UFUNCTION(BlueprintPure, Category = "Resources")
	bool CanAffordGold(int32 Amount) const { return Gold >= Amount; }

	// 扣除金币
	UFUNCTION(BlueprintCallable, Category = "Resources")
	bool SpendGold(int32 Amount);

	// ============== 遗物 / 商店系统 ==============

	// 遗物数据资产
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Relic")
	TObjectPtr<ULFPRelicDataAsset> RelicDataAsset;

	// 商店数据资产
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Shop")
	TObjectPtr<ULFPShopDataAsset> ShopDataAsset;

	// 雇佣市场数据资产
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HireMarket")
	TObjectPtr<ULFPHireMarketDataAsset> HireMarketDataAsset;

	// 已拥有遗物 ID 集合
	UPROPERTY(BlueprintReadOnly, Category = "Relic")
	TSet<FName> OwnedRelicIDs;

	// 是否已拥有遗物
	UFUNCTION(BlueprintPure, Category = "Relic")
	bool HasRelic(FName RelicID) const;

	// 尝试将遗物加入已拥有列表
	UFUNCTION(BlueprintCallable, Category = "Relic")
	bool TryAddOwnedRelic(FName RelicID);

	// 获取已拥有遗物 ID 列表
	UFUNCTION(BlueprintPure, Category = "Relic")
	TArray<FName> GetOwnedRelicIDsArray() const;

	// 查找遗物定义
	UFUNCTION(BlueprintPure, Category = "Relic")
	bool FindRelicDefinition(FName RelicID, FLFPRelicDefinition& OutDefinition) const;

	// 查找商店定义
	UFUNCTION(BlueprintPure, Category = "Shop")
	bool FindShopDefinition(FName ShopID, FLFPShopDefinition& OutDefinition) const;

	// 购买遗物
	UFUNCTION(BlueprintCallable, Category = "Shop")
	bool TryPurchaseRelic(FName RelicID, int32 Price);

	// 将已拥有遗物效果应用到单位当前属性
	UFUNCTION(BlueprintCallable, Category = "Relic")
	void ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const;

	// ============== 雇佣市场 ==============

	// 已购买的雇佣市场单位（HireMarketID -> UnitTypeID 集合）
	TMap<FName, TSet<FName>> PurchasedHireMarketUnitMap;

	// 查找雇佣市场定义
	UFUNCTION(BlueprintPure, Category = "HireMarket")
	bool FindHireMarketDefinition(FName HireMarketID, FLFPHireMarketDefinition& OutDefinition) const;

	// 是否已在指定雇佣市场购买过该单位
	UFUNCTION(BlueprintPure, Category = "HireMarket")
	bool HasPurchasedHireMarketUnit(FName HireMarketID, FName UnitTypeID) const;

	// 购买雇佣市场单位（同一市场内同种单位不可重复购买）
	UFUNCTION(BlueprintCallable, Category = "HireMarket")
	bool TryPurchaseHireMarketUnit(FName HireMarketID, FName UnitTypeID, int32 Price, FLFPUnitEntry& OutUnit);

	// 花金币购买单位（仅扣钱+生成 UnitEntry，不处理入队）
	// 返回 true 表示扣款成功，OutUnit 为生成的单位数据
	UFUNCTION(BlueprintCallable, Category = "HireMarket")
	bool TrySpendForUnit(FName UnitTypeID, int32 Price, FLFPUnitEntry& OutUnit);

	// ============== 编队系统 ==============

	// 单位注册表（蓝图中配置，全局唯一）
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
	TObjectPtr<ULFPUnitRegistryDataAsset> UnitRegistry;

	// 出战队伍
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
	TArray<FLFPUnitEntry> PartyUnits;

	// 备战营
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
	TArray<FLFPUnitEntry> ReserveUnits;

	// 出战队伍上限
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
	int32 MaxPartySize = 3;

	// 备战营上限
	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "Party")
	int32 MaxReserveSize = 3;

	// 尝试添加单位：先队伍 → 再备战 → 都满返回 false
	UFUNCTION(BlueprintCallable, Category = "Party")
	bool TryAddUnit(const FLFPUnitEntry& Unit);

	// 队伍是否已满
	UFUNCTION(BlueprintPure, Category = "Party")
	bool IsPartyFull() const { return PartyUnits.Num() >= MaxPartySize; }

	// 备战营是否已满
	UFUNCTION(BlueprintPure, Category = "Party")
	bool IsReserveFull() const { return ReserveUnits.Num() >= MaxReserveSize; }

	// 替换队伍中的单位
	UFUNCTION(BlueprintCallable, Category = "Party")
	void ReplacePartyUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit);

	// 替换备战营中的单位
	UFUNCTION(BlueprintCallable, Category = "Party")
	void ReplaceReserveUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit);

	// 移除队伍单位
	UFUNCTION(BlueprintCallable, Category = "Party")
	void RemovePartyUnit(int32 SlotIndex);

	// 移除备战营单位
	UFUNCTION(BlueprintCallable, Category = "Party")
	void RemoveReserveUnit(int32 SlotIndex);

	// ============== 单位升阶 ==============

	// 查找可合并的 TypeID 列表（同 TypeID 出现 >= 2 次且注册表中有进化目标）
	UFUNCTION(BlueprintCallable, Category = "Party")
	TArray<FLFPUnitEntry> GetMergeablePairs() const;

	// 执行合并：移除指定的两个单位，添加进化目标新单位
	// TargetTypeID: 进化目标 TypeID（分支选择时由 UI 传入）
	UFUNCTION(BlueprintCallable, Category = "Party")
	bool MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
		bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID);

protected:
	// 待处理的战斗请求
	UPROPERTY()
	FLFPBattleRequest PendingBattleRequest;

	// 待处理的战斗结果
	UPROPERTY()
	FLFPBattleResult PendingBattleResult;

	// 世界地图状态快照
	UPROPERTY()
	FLFPWorldMapSnapshot WorldMapSnapshot;
};

