// ============== 静态遗物效果（部署时一次性生效） ==============

// 遗物效果类型（第一期只做稳定的战斗数值被动）
UENUM(BlueprintType)
enum class ELFPRelicEffectType : uint8
{
	RET_MaxHealthFlat UMETA(DisplayName = "最大生命"),
	RET_AttackFlat    UMETA(DisplayName = "攻击力"),
