};

// ============== 战斗遗物规则结构 ==============

// 目标筛选器
USTRUCT(BlueprintType)
struct FLFPRelicTargetFilter
{
	GENERATED_BODY()

	// 是否只作用于触发单位自身
	UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Relic|Battle Rule")
