131	bool ULFPGameInstance::SpendGold(int32 Amount)
132	{
133		if (Amount < 0)
134		{
135			return false;
136		}
137	
138		if (!CanAffordGold(Amount))
139		{
140			UE_LOG(LogTemp, Warning, TEXT("金币不足: 需要 %d, 当前 %d"), Amount, Gold);
141			return false;
142		}
