388	
389	TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
390	{
391		// 统计每个 TypeID 的出现次数
392		TMap<FName, int32> CountMap;
393	
394		for (const FLFPUnitEntry& Unit : PartyUnits)
395		{
396			if (Unit.IsValid())
397			{
398				CountMap.FindOrAdd(Unit.TypeID, 0)++;
399			}
400		}
401		for (const FLFPUnitEntry& Unit : ReserveUnits)
402		{
403			if (Unit.IsValid())
404			{
405				CountMap.FindOrAdd(Unit.TypeID, 0)++;
406			}
407		}
408	
409		// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
410		TArray<FLFPUnitEntry> Result;
411		for (const auto& Pair : CountMap)
412		{
413			if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
414			{
415				FLFPUnitEntry Entry;
416				Entry.TypeID = Pair.Key;
417				Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
418				Result.Add(Entry);
419			}
420		}
421	
422		return Result;
423	}
424	
425	bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
426		bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
427	{
428		TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
429		TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
430	
431		if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
432		{
433			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
434			return false;
435		}
436	
437		const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
438		const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
439	
440		// 验证两个源单位 TypeID 相同
441		if (UnitA.TypeID != UnitB.TypeID)
442		{
443			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
444				*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
445			return false;
446		}
447	
448		// 验证 TargetTypeID 在进化目标列表中
449		if (!UnitRegistry)
450		{
451			UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
452			return false;
453		}
454	
455		TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
456		if (!Targets.Contains(TargetTypeID))
457		{
458			UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
459				*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
460			return false;
461		}
462	
463		// 创建进化后的新单位
464		FLFPUnitEntry NewUnit;
465		NewUnit.TypeID = TargetTypeID;
466		NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
467	
468		// 移除两个源单位（同一数组时先移除大索引避免偏移）
469		if (bSourceAIsParty == bSourceBIsParty)
470		{
471			int32 First = FMath::Max(SourceAIndex, SourceBIndex);
472			int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
473			ArrayA.RemoveAt(First);
474			ArrayA.RemoveAt(Second);
475		}
476		else
477		{
478			ArrayA.RemoveAt(SourceAIndex);
479			ArrayB.RemoveAt(SourceBIndex);
480		}
481	
482		TryAddUnit(NewUnit);
483	
484		UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
485			*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
486	
487		return true;
488	}
