	FString LevelName = BattleLevelName.IsEmpty() ? DefaultBattleLevelName : BattleLevelName;
	UE_LOG(LogTemp, Log, TEXT("切换到战斗关卡: %s"), *LevelName);

	// 淡出到黑
	UWorld* World = GetWorld();
