		UE_LOG(LogTemp, Warning, TEXT("雇佣市场配置不存在: %s"), *HireMarketNode->HireMarketID.ToString());
		if (bReturnToTownOnClose && TownWidget && TownWidget->IsInViewport())
		{
			TownWidget->SetVisibility(ESlateVisibility::Visible);
		}
